/*
 * tanhf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly tanhf  (test_tanhf_opt.elf)
 *   2. Linked with toolchain's default tanhf        (test_tanhf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += tanhf(vx);
#else
    float r = tanhf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf -> tanhf = +1.0 */
    emit_u(0xff800000u);  /* -Inf -> tanhf = -1.0 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(FLT_MIN);        /* 2^-126: smallest normal positive */
    emit(-FLT_MIN);
    emit_u(0x7f7fffffu);  /* FLT_MAX: tanhf saturates to 1.0 */
    emit_u(0xff7fffffu);  /* -FLT_MAX: tanhf saturates to -1.0 */

    /* --- Section 4: Near 1.0 ULP density (6) --- */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    emit(1.0f);
    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
    emit(-1.0f);

    /* --- Section 5: Near-zero fast-path thresholds (8) --- */
    /* tanh(x) ~ x for tiny x; test boundaries of this fast path */
    emit_u(0x33800000u);  /* 2^-24: near single-precision epsilon */
    emit_u(0xb3800000u);  /* -2^-24 */
    emit_u(0x39800000u);  /* 2^-12 */
    emit_u(0xb9800000u);  /* -2^-12 */
    emit_u(0x3c800000u);  /* 2^-6 */
    emit_u(0xbc800000u);  /* -2^-6 */
    emit(1.0e-10f);
    emit(-1.0e-10f);

    /* --- Section 6: Mathematical key values (14) --- */
    emit(0.25f);           /* tanh(0.25) ~ 0.2449 */
    emit(-0.25f);
    emit(0.5f);            /* tanh(0.5) ~ 0.4621 */
    emit(-0.5f);
    emit_u(0x3f317218u);   /* ln2 ~ 0.6931: tanh(ln2) = 3/5 */
    emit_u(0xbf317218u);   /* -ln2 */
    emit(1.0f);            /* tanh(1.0) ~ 0.7616 */
    emit(-1.0f);           /* duplicate of S4 avoided: this is kept for S6 grouping -- replaced with 1.25 */
    emit(1.5f);            /* tanh(1.5) ~ 0.9051 */
    emit(-1.5f);
    emit(2.0f);            /* tanh(2.0) ~ 0.9640 */
    emit(-2.0f);
    emit(2.5f);            /* tanh(2.5) ~ 0.9866 */
    emit(-2.5f);

    /* --- Section 7: Polynomial branch boundary ULP triplets (9) --- */
    /* Many tanhf implementations switch polynomial near x~0.54 and x~2.0 */
    emit_u(0x3f0a3d71u);  /* ~0.5399: just below typical branch point ~0.54 */
    emit_u(0x3f0a3d72u);  /* ~0.5399 + 1 ULP */
    emit_u(0x3f0a3d73u);  /* ~0.5399 + 2 ULP */
    emit_u(0xbf0a3d71u);  /* negative of above */
    emit_u(0x40000000u);  /* 2.0: exponent boundary, often a branch point */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
    emit_u(0x40000001u);  /* one ULP above 2.0 */
    emit_u(0xbfffffffu);  /* one ULP below -2.0 (toward zero) */
    emit_u(0xc0000001u);  /* one ULP above -2.0 (away from zero) */

    /* --- Section 8: Saturation stress (12) --- */
    /* tanhf saturates to +-1.0 for large |x|; test convergence region */
    emit(3.0f);
    emit(-3.0f);
    emit(3.5f);
    emit(-3.5f);
    emit(4.0f);
    emit(-4.0f);
    emit(4.5f);
    emit(-4.5f);
    emit(5.0f);
    emit(-5.0f);
    emit(10.0f);
    emit(-10.0f);

    /* --- Section 9: ULP triplets at key values (15) --- */
    /* pi/4 ~ 0.7854 */
    emit_u(0x3f490fdau);  /* one ULP below pi/4 */
    emit_u(0x3f490fdbu);  /* pi/4 */
    emit_u(0x3f490fdcu);  /* one ULP above pi/4 */
    /* pi/2 ~ 1.5708 */
    emit_u(0x3fc90fdau);  /* one ULP below pi/2 */
    emit_u(0x3fc90fdbu);  /* pi/2 */
    emit_u(0x3fc90fdcu);  /* one ULP above pi/2 */
    /* negative pi/4 */
    emit_u(0xbf490fdau);  /* one ULP toward zero from -pi/4 */
    emit_u(0xbf490fdbu);  /* -pi/4 */
    emit_u(0xbf490fdcu);  /* one ULP away from zero from -pi/4 */
    /* 0.5 exact and ULP neighbors */
    emit_u(0x3efffffff);  /* one ULP below 0.5 -- note: 0.5 = 0x3f000000 */
    emit_u(0x3f000000u);  /* 0.5 */
    emit_u(0x3f000001u);  /* one ULP above 0.5 */
    emit_u(0xbf000001u);  /* one ULP above -0.5 (toward zero) */
    emit_u(0xbf000000u);  /* -0.5 */
    emit_u(0xbeffffffu);  /* one ULP below -0.5 (toward zero) */

    /* --- Section 10: Exponent switching and hard-case mix (19) --- */
    emit(0.125f);          /* 2^-3: exercises lower polynomial branch */
    emit(-0.125f);
    emit(0.375f);
    emit(-0.375f);
    emit(0.625f);
    emit(-0.625f);
    emit(0.75f);
    emit(-0.75f);
    emit(0.875f);
    emit(-0.875f);
    emit(1.25f);
    emit(-1.25f);
    emit(1.75f);
    emit(-1.75f);
    emit(100.0f);          /* deep saturation, result = 1.0f exactly */
    emit(-100.0f);
    emit_u(0x00800001u);   /* one ULP above FLT_MIN */
    emit_u(0x3e800000u);   /* 0.25 via exponent boundary: 2^-2 = 0.25 */
    emit_u(0x3e000000u);   /* 0.125 via exponent boundary: 2^-3 */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 4] and [-4, 0] in 200 steps each */
static void test_sweep(void)
{
    float hi = 4.0f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 4] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-4, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf g_acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

